const path = require('path');
let findRoot = require('find-root');

const FileUtils = require('../lib/jibo-cai-utils').FileUtils;

const ROOT = findRoot(module.filename);

describe('FileUtils', () => {

	it('readFile exists', (done) => {
		let basePath = path.join(ROOT , 'resources_test', 'bar1.ts');
		console.log(basePath);
		FileUtils.readFile(basePath)
		.then( (data) => {
			expect(data).to.equal('test');
			done();
		}).catch(done);
	});

	it(`readFile doesn't exists`, (done) => {
		let basePath = path.join(ROOT , 'resources_test', 'bar2.ts');
		FileUtils.readFile(basePath)
			.then( () => done('error') )
			.catch( () => done() );
	});

	it('readFile small chunk size', (done) => {
		let basePath = path.join(ROOT , 'resources_test', 'bar1.ts');
		console.log(basePath);
		FileUtils.readFile(basePath, 'utf8', 2)
			.then( (data) => {
				expect(data).to.equal('test');
				done();
			}).catch(done);
	});

	it('findAllFilesWithExt', (done) => {
		let basePath = ROOT + '/resources_test';
		FileUtils.findAllFilesWithExt( basePath, 'ts')
		.then( (files) => {
			let baseFiles = files.map(f => path.basename(f));
			expect(baseFiles).to.deep.equal(['bar1.ts', 'bar2.ts']);
			done();
		}).catch(done);
	});

	it('_gatherBackwardPaths', (done) => {
		let out = [];
		FileUtils._gatherBackwardPaths('/root/next1/next2/next3', out);
		expect(out).to.deep.equal([
			path.resolve('/root/next1/next2/next3'),
			path.resolve('/root/next1/next2'),
			path.resolve('/root/next1'),
			path.resolve('/root'),
			path.resolve('/') ]);
		done();
	});

	it('searchBackward1', (done) => {
		let dir = path.dirname(__filename);
		FileUtils.searchBackwardInPath(dir, 'src')
			.then( result => {
				expect(result.endsWith('src')).to.be.true;
				done();
			}).catch(done);
	});

	it('searchBackward2', (done) => {
		let dir = path.dirname(__filename);
		FileUtils.searchBackwardInPath(dir, 'find-root')
			.then( result => {
				expect(result).to.eq(null);
				return FileUtils.searchBackwardInPath(dir, 'find-root', ['node_modules']);
			}).then( result => {
				let name = path.join('node_modules', 'find-root');
				expect(result.endsWith(name)).to.be.true;
				done();
			}).catch(done);

	});

});
